select m.id, m.site_id, s.name as site_name, m.category_id, c.name as category_name, c.icon as category_icon, CASE WHEN c.is_section = '1' THEN c.id ELSE c.parent_id END as section_id, CASE WHEN c.is_section = '1' THEN c.name ELSE pc.name END as section_name, m.is_ai_generated, m.prompt_template_id, m.generation_count, m.last_generation_id, m.is_top, m.is_recommend, m.sort_order, m.del_flag, m.create_by, m.create_time, m.update_by, m.update_time, m.publish_time, m.remark, a.title as article_title, a.cover_url as article_cover_url, a.author as article_author, a.slug as article_slug, a.storage_config_id as article_storage_config_id, a.storage_url as article_storage_url, a.view_count as article_view_count, a.locale as article_locale, -- 统一的可见性状态（基于文章状态） -- 1. 自有文章（site_id = 当前网站）：始终可见 -- 2. 默认配置（site_id = 0）： -- - 如果有关联记录（incl.id不为空），使用关联表的is_visible（忽略排除逻辑） -- - 如果没有关联记录，使用排除逻辑（有excl记录则不可见，否则可见） -- 3. 其他网站文章：使用关联表的is_visible（必须有关联记录才能访问） CASE WHEN m.site_id = #{siteId} THEN '1' WHEN m.site_id = #{params.personalSiteId} THEN (CASE WHEN incl.id IS NOT NULL THEN incl.is_visible WHEN excl.id IS NULL THEN '1' ELSE '0' END) ELSE coalesce(incl.is_visible, '0') END as is_visible, -- 关联来源标识 CASE WHEN m.site_id = #{siteId} THEN 'own' WHEN m.site_id = #{params.personalSiteId} THEN 'default' ELSE 'shared' END as relation_source, -- 是否被排除（仅对默认配置且无关联记录时有效） CASE WHEN m.site_id = #{params.personalSiteId} AND incl.id IS NULL AND excl.id IS NOT NULL THEN '1' ELSE '0' END as is_excluded, -- 关联的网站数量（仅对非默认配置计算，排除自己所属网站） CASE WHEN m.site_id = #{params.personalSiteId} THEN NULL ELSE (SELECT COUNT(*) FROM gb_site_master_article_relations r WHERE r.master_article_id = m.id AND r.relation_type = 'include' AND r.site_id != m.site_id) END as related_sites_count, -- 排除的网站数量 (SELECT COUNT(*) FROM gb_site_master_article_relations r WHERE r.master_article_id = m.id AND r.relation_type = 'exclude') as excluded_sites_count from gb_master_articles m left join gb_categories c on m.category_id = c.id and c.del_flag = '0' left join gb_categories pc on c.parent_id = pc.id and pc.del_flag = '0' and pc.is_section = '1' left join gb_sites s on m.site_id = s.id left join gb_articles a on a.master_article_id = m.id and a.locale = COALESCE(s.default_locale, 'zh-CN') and a.del_flag = '0' -- 左连接正向关联（include） LEFT JOIN gb_site_master_article_relations incl ON m.id = incl.master_article_id AND incl.site_id = #{siteId} AND incl.relation_type = 'include' -- 左连接排除关联（exclude） LEFT JOIN gb_site_master_article_relations excl ON m.id = excl.master_article_id AND excl.site_id = #{siteId} AND excl.relation_type = 'exclude'
m.del_flag = '0'
AND ( m.site_id = #{siteId}
OR m.site_id = #{params.personalSiteId}
OR (m.site_id != #{siteId}
AND m.site_id != #{params.personalSiteId}
AND incl.id IS NOT NULL) ) and m.category_id = #{categoryId} and (c.parent_id = #{sectionId} or (c.is_section = '1' and c.id = #{sectionId})) and a.title like concat('%', #{title}, '%') and m.is_ai_generated = #{isAiGenerated} and m.is_top = #{isTop} and m.is_recommend = #{isRecommend}
and date_format(m.create_time,'%y%m%d') >= date_format(#{params.beginTime},'%y%m%d')
and date_format(m.create_time,'%y%m%d') <= date_format(#{params.endTime},'%y%m%d')
order by m.is_top desc, m.sort_order asc, m.create_time desc



    m.del_flag = '0'



            AND (m.site_id = #{siteId} OR m.site_id = #{params.personalSiteId})



            AND m.site_id = #{siteId}



            AND m.site_id = #{params.personalSiteId}


            AND 1 = 0


     and m.category_id = #{categoryId}
     and (c.parent_id = #{sectionId} or (c.is_section = '1' and c.id = #{sectionId}))
     and a.title like concat('%', #{title}, '%')
     and m.is_ai_generated = #{isAiGenerated}
     and m.is_top = #{isTop}
     and m.is_recommend = #{isRecommend}

        and date_format(m.create_time,'%y%m%d') >= date_format(#{params.beginTime},'%y%m%d')


        and date_format(m.create_time,'%y%m%d') <= date_format(#{params.endTime},'%y%m%d')


order by m.is_top desc, m.sort_order asc, m.create_time desc

