update gb_master_articles
site_id = #{siteId}, category_id = #{categoryId}, is_ai_generated = #{isAiGenerated}, prompt_template_id = #{promptTemplateId}, generation_count = #{generationCount}, last_generation_id = #{lastGenerationId}, is_top = #{isTop}, is_recommend = #{isRecommend}, sort_order = #{sortOrder}, del_flag = #{delFlag}, update_by = #{updateBy}, update_time = #{updateTime}, publish_time = #{publishTime}, remark = #{remark},
where id = #{id}
